    const auto json1 = rfl::json::write(student1);
    const auto json2 = rfl::json::write(student_records);
    EXPECT_EQ(json2, json1);
  }

  {
    auto result = exec(conn, "SELECT * FROM Student WHERE SNo='S002';");
    ASSERT_TRUE(result);

