#include <string>
#include <vector>
#include <sstream>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

// Helper function to get primary key column name for each table
inline std::string get_primary_key_column(const std::string& table_name) {
  static const std::map<std::string, std::string> pk_map = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };
  return pk_map.at(table_name);
}

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  for (const auto& record : records) {
    sqlgen::insert(conn, record).value();
  }
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const T& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  std::string pk_col = get_primary_key_column(table_name);

  // Construct UPDATE SQL statement
  std::ostringstream sql;
  sql << "UPDATE " << table_name << " SET " << col_name << " = '" 
      << new_value << "' WHERE " << pk_col << " = '" << record_id << "'";

  sqlgen::exec(conn, sql.str()).value();
}

// Specialization for numeric types to avoid quotes
template<>
inline void modify_eas_records_by_id<int>(const std::string& table_name,
                                           const std::string& record_id,
                                           const std::string& col_name,
                                           const int& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  std::string pk_col = get_primary_key_column(table_name);

  std::ostringstream sql;
  sql << "UPDATE " << table_name << " SET " << col_name << " = " 
      << new_value << " WHERE " << pk_col << " = '" << record_id << "'";

  sqlgen::exec(conn, sql.str()).value();
}

template<>
inline void modify_eas_records_by_id<double>(const std::string& table_name,
                                              const std::string& record_id,
                                              const std::string& col_name,
                                              const double& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  std::string pk_col = get_primary_key_column(table_name);

  std::ostringstream sql;
  sql << "UPDATE " << table_name << " SET " << col_name << " = " 
      << new_value << " WHERE " << pk_col << " = '" << record_id << "'";

  sqlgen::exec(conn, sql.str()).value();
}

template<>
inline void modify_eas_records_by_id<uint32_t>(const std::string& table_name,
                                                const std::string& record_id,
                                                const std::string& col_name,
                                                const uint32_t& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  std::string pk_col = get_primary_key_column(table_name);

  std::ostringstream sql;
  sql << "UPDATE " << table_name << " SET " << col_name << " = " 
      << new_value << " WHERE " << pk_col << " = '" << record_id << "'";

  sqlgen::exec(conn, sql.str()).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  std::string pk_col = get_primary_key_column(table_name);

  // Construct DELETE SQL statement
  std::ostringstream sql;
  sql << "DELETE FROM " << table_name << " WHERE " << pk_col << " = '" << record_id << "'";

  sqlgen::exec(conn, sql.str()).value();
}
