  sqlgen::Table<Customer> c("Customer");

  // Build the query with INNER JOIN
  auto query = sqlgen::select(
      o.field(&Order::order_id),
      c.field(&Customer::name),
      o.field(&Order::total_amount),
      o.field(&Order::order_date)
    )
    .from(o)
    .inner_join(c).on(o.field(&Order::customer_id) == c.field(&Customer::customer_id))
    .where(o.field(&Order::total_amount) > 1000.0)
    .order_by(o.field(&Order::total_amount), sqlgen::DESC);

  // Execute query and collect results
  std::vector<OrderView> results;
  auto result_set = db.execute(query);

  for (auto& row : result_set) {
    OrderView view;
    view.order_id = row.get<int>(0);
    view.name = row.get<std::string>(1);
    view.total_amount = row.get<double>(2);
    view.order_date = row.get<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">>(3);
    results.push_back(view);
  }

  return results;
}

