    auto product = sqlgen::define_table<Product>("Product");
    auto sale = sqlgen::define_table<Sale>("Sale");

    // Build the query with join, grouping, and filtering
    auto query = sqlgen::select(
        product.category,
        sqlgen::sum(sale.quantity).as("total_qty"),
        sqlgen::sum(sale.amount).as("total_amt")
    )
    .from(product)
