};

/**
 * Function: Create a table with various constraints and data types.
 * 
 * @return true if creation succeeds, false otherwise
 */
bool create_complex_table() {
  try {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::open("test_db.sqlite");

    // Define table schema with constraints
    auto schema = sqlgen::define_table<UserProfile>(
      sqlgen::column("user_id", &UserProfile::user_id),
      sqlgen::column("username", &UserProfile::username, 
                     sqlgen::varchar(50), sqlgen::not_null()),
      sqlgen::column("email", &UserProfile::email, 
                     sqlgen::varchar(100), sqlgen::not_null()),
      sqlgen::column("age", &UserProfile::age, 
                     sqlgen::check("age >= 18")),
      sqlgen::column("bio", &UserProfile::bio),
      sqlgen::column("created_at", &UserProfile::created_at, 
                     sqlgen::default_value("CURRENT_TIMESTAMP")),
      sqlgen::column("is_verified", &UserProfile::is_verified, 
                     sqlgen::default_value(0))
    );

    // Create the table
    sqlgen::create_table(db, schema);

    return true;
  } catch (const std::exception& e) {
    // Log error if needed: e.what()
    return false;
  } catch (...) {
    return false;
  }
}

}  // namespace schema_create_complex_table
