std::vector<DepProj> right_join_departments_projects() {
  // Open SQLite database connection
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // SQLite doesn't natively support RIGHT JOIN, so we simulate it using LEFT JOIN
  // To demonstrate RIGHT JOIN behavior that includes all departments:
  // We use LEFT JOIN from Department to Project, which includes all departments
  // even those without projects
  // 
  // Note: Based on the DepProj struct where department_name is optional,
  // this returns all projects with their associated department (if any)
  std::string query = 
    "SELECT d.name as department_name, p.name as project_name "
    "FROM Project p "
    "LEFT JOIN Department d ON p.department_id = d.department_id";

  // Execute query and map results to DepProj structs
  auto results = conn.read<DepProj>(query);

  return results;
}

}  // namespace right_join_departments_projects
