  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  // Create SQLite connection (for schema info, queries won't be executed)
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Define table references
  sqlgen::Table<A> table_a("A");
  sqlgen::Table<B> table_b("B");

  // Build complex query with joins, where, order_by, and limit
  auto query = sqlgen::select(table_a, table_b)
    .from(table_a)
    .inner_join(table_b)
    .on(table_a.id == table_b.a_id)
    .where(table_b.score > 10.0)
    .where(table_a.name.like("%x%"))
    .order_by(table_b.score, sqlgen::Order::DESC)
    .limit(10);

  // Generate SQL string for SQLite (dry run - not executed)
  std::string sql = sqlgen::to_sql(query, sqlgen::sqlite::Dialect{});

  // Return the generated SQL string for debugging/verification
  return sql;
}

}  // namespace generate_sql_dry_run
```

