#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  sqlgen::Unique<std::string> username;
  sqlgen::Unique<std::string> email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user_id1;
  int user_id2;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

// Additional result structures for various queries
struct MutualFriendResult {
  std::string username1;
  std::string username2;
  int mutual_friends;
};

struct UserFriendCount {
  int user_id;
  std::string username;
  int friend_count;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Drop existing tables if they exist
  db.execute("DROP TABLE IF EXISTS Friendship");
  db.execute("DROP TABLE IF EXISTS User");

  // Create User table
  db.create_table<User>("User");

  // Create Friendship table with composite primary key
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1 INTEGER NOT NULL,
      user_id2 INTEGER NOT NULL,
      friendship_date TEXT NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    )
  )");

  // Insert users
  auto user_table = db.table<User>("User");
  for (const auto& user : users) {
    user_table.insert(user);
  }

  // Insert friendships
  for (const auto& friendship : friendships) {
    db.execute(
      "INSERT INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)",
      friendship.user_id1, friendship.user_id2, friendship.friendship_date
    );
  }

  std::cout << "=== Social Network Analysis ===" << std::endl;
  std::cout << "Total Users: " << users.size() << std::endl;
  std::cout << "Total Friendships: " << friendships.size() << std::endl << std::endl;

  // Query 1: Find mutual friends using SELF-JOIN
  std::cout << "=== 1. Mutual Friends (SELF-JOIN) ===" << std::endl;
  auto mutual_friends_query = db.query<MutualFriendResult>(R"(
    SELECT u1.username as username1, u2.username as username2, COUNT(f1.user_id2) as mutual_friends
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
    GROUP BY u1.user_id, u2.user_id
    HAVING COUNT(f1.user_id2) > 0
    ORDER BY mutual_friends DESC
  )");

  auto mutual_friends_results = mutual_friends_query.execute();
  for (const auto& result : mutual_friends_results) {
    std::cout << result.username1 << " and " << result.username2 
              << " have " << result.mutual_friends << " mutual friend(s)" << std::endl;
  }

  // Query 2: Find users with more than average number of friends (nested query)
  std::cout << "\n=== 2. Popular Users (Nested Query - Above Average) ===" << std::endl;
  auto popular_users_query = db.query<UserFriendCount>(R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)
    )
    ORDER BY friend_count DESC
  )");

  auto popular_users = popular_users_query.execute();
  for (const auto& user : popular_users) {
    std::cout << user.username << " has " << user.friend_count << " friends" << std::endl;
  }

  // Query 3: Find friend-of-friend relationships (not direct friends)
  std::cout << "\n=== 3. Friend-of-Friend Suggestions ===" << std::endl;
  auto fof_query = db.query<FriendConnection>(R"(
    SELECT DISTINCT u1.username as user1_name, u3.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u3 ON f2.user_id2 = u3.user_id
    WHERE u1.user_id < u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
      )
    ORDER BY u1.username, u3.username
  )");

  auto fof_results = fof_query.execute();
  for (const auto& fof : fof_results) {
    std::cout << fof.user1_name << " -> " << fof.user2_name 
              << " (connected through mutual friend)" << std::endl;
  }

  // Query 4: Count friends per user and identify most connected users
  std::cout << "\n=== 4. Friend Count Statistics (Aggregation) ===" << std::endl;
  auto all_friend_counts = db.query<UserFriendCount>(R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
    LIMIT 10
  )");

  auto friend_counts = all_friend_counts.execute();
  std::cout << "Top 10 Most Connected Users:" << std::endl;
  for (const auto& user : friend_counts) {
    std::cout << user.username << ": " << user.friend_count << " friend(s)" << std::endl;
  }

  // Query 5: Find users in the same city who are not yet friends (recommendation)
  std::cout << "\n=== 5. Same City Recommendations (Nested Query) ===" << std::endl;
  auto city_recommendations = db.query<FriendConnection>(R"(
    SELECT u1.username as user1_name, u2.username as user2_name
    FROM User u1
    INNER JOIN User u2 ON u1.city = u2.city
    WHERE u1.user_id < u2.user_id
      AND u1.city IS NOT NULL
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      )
    ORDER BY u1.username
  )");

  auto city_recs = city_recommendations.execute();
  for (const auto& rec : city_recs) {
    std::cout << rec.user1_name << " <-> " << rec.user2_name 
              << " (same city)" << std::endl;
  }

  // Additional: Network statistics
  std::cout << "\n=== Network Statistics ===" << std::endl;
  auto stats = db.query_single<int>(
    "SELECT COUNT(DISTINCT user_id1) FROM Friendship"
  );
  std::cout << "Users with at least one friend: " << stats.value_or(0) << std::endl;

  auto avg_friends = db.query_single<double>(
    "SELECT AVG(friend_count) FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)"
  );
  std::cout << "Average friends per user: " << avg_friends.value_or(0.0) << std::endl;

  auto max_friends = db.query_single<int>(
    "SELECT MAX(friend_count) FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)"
  );
  std::cout << "Maximum friends: " << max_friends.value_or(0) << std::endl;

  std::cout << "\n=== Analysis Complete ===" << std::endl;

  // Return friend-of-friend suggestions as the primary result
  return fof_results;
}

}  // namespace analyze_social_network

