  EXPECT_DOUBLE_EQ(m2.discount_rate, 0.0);
  EXPECT_DOUBLE_EQ(m2.tax_rate, 0.0);

  const auto& m3 = metrics[2];
  EXPECT_EQ(m3.item_id, 3);
  EXPECT_DOUBLE_EQ(m3.final_total, 3200.0);
