#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::open("test_db.sqlite");

    // Create Account table
    db.create_table<Account>("Account");

    // Insert initial test data
    db.insert("Account")
      .set(&Account::account_id, 1)
      .set(&Account::balance, 1000.0)
      .set(&Account::status, std::string("active"))
      .execute();

    db.insert("Account")
      .set(&Account::account_id, 2)
      .set(&Account::balance, 2000.0)
      .set(&Account::status, std::string("active"))
      .execute();

    db.insert("Account")
      .set(&Account::account_id, 3)
      .set(&Account::balance, 500.0)
      .set(&Account::status, std::string("inactive"))
      .execute();

    // Update balances and statuses using set(...)
    // Update account 1: increase balance and change status to premium
    db.update("Account")
      .set(&Account::balance, 1500.0)
      .set(&Account::status, std::string("premium"))
      .where(&Account::account_id, 1)
      .execute();

    // Update account 2: decrease balance
    db.update("Account")
      .set(&Account::balance, 1800.0)
      .where(&Account::account_id, 2)
      .execute();

    // Update account 3: activate account
    db.update("Account")
      .set(&Account::status, std::string("active"))
      .where(&Account::account_id, 3)
      .execute();

    // Verify changes persisted
    auto results = db.select<Account>()
      .from("Account")
      .execute();

    if (results.size() != 3) {
      return false;
    }

    // Check account 1
    bool account1_verified = false;
    bool account2_verified = false;
    bool account3_verified = false;

    for (const auto& account : results) {
      if (account.account_id.value == 1) {
        if (account.balance == 1500.0 && account.status == "premium") {
          account1_verified = true;
        }
      } else if (account.account_id.value == 2) {
        if (account.balance == 1800.0 && account.status == "active") {
          account2_verified = true;
        }
      } else if (account.account_id.value == 3) {
        if (account.balance == 500.0 && account.status == "active") {
          account3_verified = true;
        }
      }
    }

    return account1_verified && account2_verified && account3_verified;

  } catch (const std::exception& e) {
    return false;
  }
}

}  // namespace update_set_operations

