```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it using UNION
  // This combines:
  // 1. LEFT JOIN: All suppliers with their products (or NULL if no product)
  // 2. Products without matching suppliers (orphaned products)
  std::string query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION
    SELECT COALESCE(s.name, '') as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  std::vector<SupProd> results;

  // Execute query and process results
  auto stmt = db.prepare(query);
  while (stmt.step()) {
    SupProd sp;

    // Get supplier name (use empty string for orphaned products)
    sp.supplier_name = stmt.column<std::string>(0).value_or("");

    // Get product name (optional - NULL for suppliers without products)
    auto product_name_opt = stmt.column<std::string>(1);
    if (product_name_opt.has_value()) {
      sp.product_name = product_name_opt.value();
    }

    results.push_back(sp);
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the database** using `sqlgen::sqlite::Database`
2. **Simulates FULL OUTER JOIN** since SQLite doesn't support it natively by using:
   - `LEFT JOIN` to get all suppliers with their products (NULL if no match)
   - `UNION` with a query that finds products without matching suppliers
3. **Processes results** into `SupProd` structs:
   - Suppliers without products: `supplier_name` populated, `product_name` is `nullopt`
   - Products with suppliers: both fields populated
   - Orphaned products (no supplier): empty string for `supplier_name`, `product_name` populated
4. **Returns** the complete result set as a vector

