};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // SQL query to extract weekday and aggregate quantities
  // strftime('%w', sale_time) returns weekday as 0-6 (0=Sunday, 1=Monday, ..., 6=Saturday)
  std::string query = 
    "SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday, "
    "SUM(quantity) as total_quantity "
    "FROM Sales "
    "GROUP BY strftime('%w', sale_time) "
    "ORDER BY weekday";

  // Execute query and collect results
  std::vector<WeekdayStats> results;
  auto stmt = db.prepare(query);

  while (stmt.step()) {
    WeekdayStats stats;
    stats.weekday = stmt.get<int>(0);
    stats.total_quantity = stmt.get<int>(1);
    results.push_back(stats);
  }

  return results;
}

}  // namespace weekday_sales_analysis

